<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                        <h4 class="modal-title">{{ $t('Manage') }} {{ $t('Stage') }} </h4>
                        <button type="button" class="close" v-on:click="CloseStage">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>
                    </div>
                    <div class="modal-body">
                        <dynamic-form lang="en" :buttons="buttons" :schema="FormSchema" ref="AssignTagForm"
                            :mandatorytext='MandatoryString' v-on:OnSubmit="OnSubmit"></dynamic-form>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import DataService from '../../../services/DataService';
export default {
    props: {
        EditStageData: {
            type: Object,
            required: true
        }
    },  
    data() {
        return {
            isLoading: false,
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            StageId:0,
            FormSchema: [
                {
                    layoutType: "double",
                    Data: [
                        {
                            astype: "TextField",
                            label: this.$t('Stage Name'),
                            name: "StageName",
                            value: "",
                            placeholder: this.$t('Enter Stage Name'),
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('Phase Name'),
                            value: "",
                            config: {
                                options: []
                            },
                            placeholder: this.$t('Select Phase Name'),
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('Type'),
                            value: "Project",
                            disabled: true,
                            config: {
                                options: []
                            },
                            placeholder: this.$t('Select Type'),
                            validationRules: { "required": false, max: 100 },
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('Status'),
                            name: "Tag",
                            value: "",
                            config: {
                                options: [{name:'Active',value:1001 },{name:'Inactive',value:1002}]
                            },
                            placeholder: this.$t('Select Status'),
                            validationRules: { "required": false, max: 100 },
                        }
                    ]
                },
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "TextAreaField",
                            label: this.$t('Description'),
                            name: "Description",
                            value: "",
                            validationRules: { "required": false, max: 4000 },
                            config: {
                                rows: 5
                            }
                        }
                    ]
                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    isVisible: true,
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.CloseStage,
                },
            ]
        }
    },
    created: function () {
        var ths = this;
        ths.BindPhaseDropdown();
        ths.GetStageType();
        // ths.GetStatusList();
        if(ths.EditStageData != null) {
            ths.BindStageDetails();
        }
    },
    methods: {
        BindStageDetails: function () {
            debugger
            var ths = this;
            ths.StageId = ths.EditStageData.STAGE_ID;
            ths.FormSchema[0].Data[0].value = ths.EditStageData.STAGE_NAME;
            ths.FormSchema[0].Data[1].value = ths.EditStageData.PHASE_ID;
            ths.FormSchema[0].Data[2].value = ths.EditStageData.STAGE_TYPE;
            ths.FormSchema[0].Data[3].value = ths.EditStageData.STATUS_ID;
            ths.FormSchema[1].Data[0].value = ths.EditStageData.STAGE_DESC
        },
        CloseStage() {
            this.$emit('CloseStageModel');
        },
        BindPhaseDropdown: function () {
            var ths = this;
            var url = `id=&moduleName=&type=PHASE_NAME&search=&refId=0`;
            DataService.GetDDLData(url).then((response) => {
                if (response.data.DATA.length > 0) {
                    response.data.DATA.forEach((item) => {
                        let obj = {
                            name: item.name.length > 20 ? item.name.substring(0, 80) + '...' : item.name,
                            value: item.value,                           
                        }
                        ths.FormSchema[0].Data[1].config.options.push(obj);                        
                    })
                    ths.$refs.AssignTagForm.UpdateKeyValue();
                }
            })
        },
        GetStageType: function () {
            var ths = this;
            DataService.GetStageType().then((response) => {
                if (response.data.result.DATA.length > 0) {
                    response.data.result.DATA.forEach((item) => {
                        let obj = {
                            name: item.MODULE_NAME,
                            value: item.MODULE_NAME
                        }
                        ths.FormSchema[0].Data[2].config.options.push(obj);
                        
                    })
                    ths.$refs.AssignTagForm.UpdateKeyValue();
                }
            })
        },
        GetStatusList: async function () {
            var vm = this;
            var params = `statusType=${"Project"}&hasglobal=${false}`;
            DataService.GetStatusList(params).then(async (response) => {
                if (response.data.length > 0) {
                    var statusList = [];
                    statusList = response.data;
                    statusList.forEach((item) => {
                        var obj = {
                            name: item.STATUS,
                            value: item.STATUS_ID
                        }
                        vm.FormSchema[0].Data[3].config.options.push(obj);
                        
                    })
                    vm.$refs.AssignTagForm.UpdateKeyValue();
                }
            });
        },
        OnSubmit: function () {
            var vm = this;
            var postString = {
                StageId: vm.StageId,
                StageName: vm.FormSchema[0].Data[0].value,
                PhaseId: vm.FormSchema[0].Data[1].value,
                StatusId: vm.FormSchema[0].Data[3].value,
                StageDescription: vm.FormSchema[1].Data[0].value,
                TypeCode: vm.FormSchema[0].Data[2].value
            };
            var objectPostString = JSON.stringify(postString);
            DataService.AddSaveStage(objectPostString).then(async (response) => {
                vm.isLoading = false;
                if (response.data.result.DATA[0].VALUE == 'INSERT') {
                    vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('Stage')]), "success", true, vm.$t("Alert"));

                } else if (response.data.result.DATA[0].VALUE == 'UPDATE') {
                    vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t('Stage')]), "success", true, vm.$t("Alert"));
                } else {
                    vm.ShowAlert(vm.$t('AlreadyExists', [vm.$t('Stage')]), "warning", true, vm.$t("Alert"));
                }
                vm.CloseStage();
            })
        }
    }
}
</script>